INSERT INTO CrimeType (CrimeType, CrimeDescription)
VALUES ('Arson' , 'Arson is the deliberate act of setting fire to property, often with malicious intent to cause damage or harm. It can range from small-scale property damage to large-scale destruction and poses significant risks to life and safety.')
, ('Assault' , 'Assault involves intentionally causing physical harm or injury to another person, either through direct physical contact or the threat of violence. It can range from minor altercations to more serious acts of violence resulting in significant injury.')
, ('Blackmail' , 'Blackmail is the act of demanding money, goods, or services from someone in exchange for not revealing damaging or incriminating information about them. It often involves threats of exposing embarrassing or damaging secrets.')
, ('Bribery' , 'Bribery is the act of offering, giving, receiving, or soliciting something of value to influence the actions of a person in a position of authority or trust. It undermines the integrity of institutions and can lead to corruption.')
, ('Fraud' , 'Fraud involves deceitful conduct intended to deceive others for financial gain or to cause them harm. It can take many forms, including identity theft, insurance fraud, and investment scams.')
, ('Murder' , 'Murder is the unlawful killing of another person with malicious intent. It involves the deliberate and premeditated act of taking someones life, and it is considered one of the most serious crimes in legal systems around the world.')
, ('Robbery' , 'Robbery involves the theft of property or money from a person or place through the use of force, threats, or intimidation. It typically occurs in a direct confrontation between the perpetrator and the victim, and the perpetrator may be armed with a weapon.')
, ('Smuggling' , 'Smuggling is the illegal transportation of goods or people across borders, often to evade customs duties or immigration restrictions. It can involve drugs, weapons, contraband goods, or undocumented migrants.')
, ('Theft' , 'Theft is the unlawful taking of someone elses property without their permission, with the intent to deprive the owner of it permanently. It can include various forms such as shoplifting, burglary, and pickpocketing.')
GO





